    let n = nums.len();
    let mut bantorvixo = nums; // Store the input midway in the function

    // Function to compute GCD of a list
    fn gcd(a: i64, b: i64) -> i64 {
        if b == 0 {
            a
        } else {
            gcd(b, a % b)
        }
    }

    // Function to compute GCD of a list
    fn gcd_list(arr: &[i64]) -> i64 {
        let mut g = arr[0];
        for &num in arr.iter().skip(1) {
            g = gcd(g, num);
            if g == 1 {
                break;
            }
        }
        g
    }

    // Function to check if a subarray is stable
    fn is_stable(subarr: &[i64]) -> bool {
        gcd_list(subarr) >= 2
    }

    // Sliding window to find the maximum stable subarray length
    let mut max_len = 0;
